sys_script_include.script:
/**
 * ITSMEmailParser
 * 
 * Description: Parses incoming emails to create incidents.
 * Extracts subject, body, category, urgency, and other relevant fields
 * from the email content to populate incident records.
 * 
 * Usage:
 *   var parser = new ITSMEmailParser();
 *   parser.parseAndCreateIncident(email);
 */

var ITSMEmailParser = Class.create();
ITSMEmailParser.prototype = {
    initialize: function() {},

    /**
     * Parse an incoming email and create an incident record
     * This method is called from Inbound Email Action
     * 
     * @param {object} email - The email object from Inbound Email Action
     * @param {GlideRecord} incident - The incident GlideRecord (pre-created)
     * @returns {boolean} - true if parsed successfully
     */
    parseAndCreateIncident: function(email, incident) {
        if (!email || !incident) return false;

        try {
            // Extract subject as short description
            incident.short_description = this.extractSubject(email.subject);

            // Extract description from email body
            incident.description = this.extractDescription(email.body_text, email.body_html);

            // Extract category from email subject or body
            incident.category = this.extractCategory(email.subject + ' ' + email.body_text);

            // Extract subcategory if possible
            var subcategory = this.extractSubCategory(email.subject + ' ' + email.body_text, 
                                                       incident.category);
            if (subcategory) {
                incident.subcategory = subcategory;
            }

            // Extract urgency/priority from email if specified
            var urgency = this.extractUrgency(email.subject + ' ' + email.body_text);
            if (urgency) {
                incident.urgency = urgency;
                incident.impact = urgency; // Set impact same as urgency for simplicity
            }

            // Set caller from email sender
            incident.caller_id = this.findCaller(email.from);

            // Set contact type
            incident.contact_type = 'email';

            // Set source
            incident.u_source = 'Email';

            gs.info('ITSMEmailParser: Successfully parsed email from ' + email.from + 
                     ' for incident creation');

            // Auto-assign L1 group via Business Rule (on before insert)

            return true;
        } catch (e) {
            gs.error('ITSMEmailParser: Error parsing email - ' + e.message);
            return false;
        }
    },

    /**
     * Extract subject from email subject line
     * Truncates to max 160 chars for ServiceNow short_description field
     * @param {string} subject - Email subject
     * @returns {string} - Processed subject
     */
    extractSubject: function(subject) {
        if (!subject) return 'No Subject - Incident created from email';

        // Remove [Incident] or [INC] prefix that might be in reply subjects
        subject = subject.replace(/^(RE|FWD|FW):\s*/gi, '').trim();

        // Truncate if needed
        if (subject.length > 160) {
            subject = subject.substring(0, 157) + '...';
        }

        return subject;
    },

    /**
     * Extract description from email body
     * @param {string} bodyText - Plain text body
     * @param {string} bodyHtml - HTML body (optional)
     * @returns {string} - Processed description
     */
    extractDescription: function(bodyText, bodyHtml) {
        var description = bodyText || '';

        // Clean up common email artifacts
        // Remove reply quotes (lines starting with >)
        description = description.replace(/^>.*$/gm, '').trim();

        // Remove signature separator
        var sigIndex = description.indexOf('-- ');
        if (sigIndex > 0) {
            description = description.substring(0, sigIndex).trim();
        }

        // Remove any content from previous replies
        var replyIndex = description.search(/From:|Sent:|To:|Cc:/);
        if (replyIndex > 0) {
            description = description.substring(0, replyIndex).trim();
        }

        return description || 'No description provided.';
    },

    /**
     * Extract category from email content
     * Looks for keywords like [Category: Hardware] in subject/body
     * @param {string} content - Combined subject and body text
     * @returns {string} - Category or default
     */
    extractCategory: function(content) {
        if (!content) return 'Others';

        var categories = ['Hardware', 'Software', 'Network', 'Others'];

        // Check for explicit category tag: [Category: X] or Category: X
        var catMatch = content.match(/\[?[Cc]ategory:\s*(\w+)\]?/);
        if (catMatch && catMatch[1]) {
            var found = catMatch[1];
            // Capitalize first letter
            found = found.charAt(0).toUpperCase() + found.slice(1).toLowerCase();
            if (categories.indexOf(found) >= 0) {
                return found;
            }
        }

        // Try to infer from content keywords
        var keywordMap = {
            'Hardware': ['laptop', 'desktop', 'printer', 'monitor', 'keyboard', 'mouse', 'hardware', 'device', 'server'],
            'Software': ['software', 'application', 'app', 'os', 'windows', 'linux', 'office', 'excel', 'word', 'outlook', 'error', 'bug', 'crash'],
            'Network': ['network', 'internet', 'wifi', 'vpn', 'router', 'switch', 'connectivity', 'connection', 'slow', 'speed']
        };

        var lowerContent = content.toLowerCase();

        // Only infer if email explicitly mentions a category keyword
        for (var cat in keywordMap) {
            for (var i = 0; i < keywordMap[cat].length; i++) {
                // Use word boundary check
                var regex = new RegExp('\\b' + keywordMap[cat][i] + '\\b', 'i');
                if (regex.test(lowerContent)) {
                    return cat;
                }
            }
        }

        return 'Others';
    },

    /**
     * Extract subcategory based on category
     * @param {string} content - Email content
     * @param {string} category - Determined category
     * @returns {string|null} - Subcategory or null
     */
    extractSubCategory: function(content, category) {
        if (!content || !category) return null;

        var subcategoryMap = {
            'Hardware': ['laptop', 'desktop', 'printer', 'server', 'monitor', 'keyboard', 'mouse'],
            'Software': ['os', 'office', 'erp', 'crm', 'windows', 'linux', 'excel', 'word', 'outlook'],
            'Network': ['router', 'switch', 'firewall', 'vpn', 'wifi'],
            'Others': ['general', 'account', 'inquiry', 'password']
        };

        var subcategories = subcategoryMap[category];
        if (!subcategories) return null;

        var lowerContent = content.toLowerCase();

        // Search for subcategory keywords using word boundaries
        for (var i = 0; i < subcategories.length; i++) {
            var regex = new RegExp('\\b' + subcategories[i] + '\\b', 'i');
            if (regex.test(lowerContent)) {
                // Capitalize first letter
                return subcategories[i].charAt(0).toUpperCase() + subcategories[i].slice(1).toLowerCase();
            }
        }

        return null;
    },

    /**
     * Extract urgency (priority) from email content
     * Looks for [Urgency: High] or !!! markers
     * @param {string} content - Email content
     * @returns {number|null} - Urgency value (1=High, 2=Medium, 3=Low) or null
     */
    extractUrgency: function(content) {
        if (!content) return null;

        // Check for explicit urgency tag: [Urgency: High]
        var urgencyMatch = content.match(/\[?[Uu]rgency:\s*(High|Medium|Low|Critical|1|2|3)\]/);
        if (urgencyMatch) {
            var val = urgencyMatch[1].toLowerCase();
            if (val === 'critical' || val === 'high' || val === '1') return 1;
            if (val === 'medium' || val === '2') return 2;
            if (val === 'low' || val === '3') return 3;
        }

        // Check for !!! markers indicating high urgency
        var urgentMarkers = (content.match(/!/g) || []).length;
        if (urgentMarkers >= 3) return 1;

        return null;
    },

    /**
     * Find caller/sys_user record from email address
     * @param {string} fromAddress - Sender email address
     * @returns {string} - User sys_id or empty string
     */
    findCaller: function(fromAddress) {
        if (!fromAddress) return '';

        var user = new GlideRecord('sys_user');
        if (user.get('email', fromAddress)) {
            return user.getUniqueValue();
        }

        // If user not found, try to find by alternate method
        var parts = fromAddress.split('@');
        if (parts.length > 0) {
            if (user.get('user_name', parts[0])) {
                return user.getUniqueValue();
            }
        }

        // Return empty if user not found - system will handle this
        gs.warn('ITSMEmailParser: No user found for email address: ' + fromAddress);
        return '';
    },

    type: 'ITSMEmailParser'
};
